/**
 * AddMedication Component
 * Modal form for adding a new medication to track
 */

import React, { useState } from "react";

function AddMedication({ onAdd, onClose }) {
  // Form state
  const [formData, setFormData] = useState({
    medicineName: "",
    totalQuantity: 30,
    dailyDosage: 1,
    startDate: new Date().toISOString().split("T")[0], // Today's date in YYYY-MM-DD format
    refillThreshold: 5,
  });

  // Error state for form validation
  const [errors, setErrors] = useState({});
  // Loading state while submitting
  const [loading, setLoading] = useState(false);

  /**
   * Handle input changes
   * Updates the formData state when user types
   */
  const handleChange = (e) => {
    const { name, value, type } = e.target;
    setFormData((prev) => ({
      ...prev,
      // Convert to number for number inputs, otherwise use string value
      [name]: type === "number" ? Number(value) : value,
    }));
    // Clear error for this field when user starts typing
    if (errors[name]) {
      setErrors((prev) => ({ ...prev, [name]: "" }));
    }
  };

  /**
   * Validate the form before submission
   * Returns true if valid, false otherwise
   */
  const validateForm = () => {
    const newErrors = {};

    // Medicine name is required
    if (!formData.medicineName.trim()) {
      newErrors.medicineName = "Medicine name is required";
    }

    // Total quantity must be positive
    if (formData.totalQuantity < 1) {
      newErrors.totalQuantity = "Quantity must be at least 1";
    }

    // Daily dosage must be positive
    if (formData.dailyDosage < 1) {
      newErrors.dailyDosage = "Daily dosage must be at least 1";
    }

    // Daily dosage shouldn't exceed total quantity
    if (formData.dailyDosage > formData.totalQuantity) {
      newErrors.dailyDosage = "Daily dosage cannot exceed total quantity";
    }

    // Start date is required
    if (!formData.startDate) {
      newErrors.startDate = "Start date is required";
    }

    // Threshold must be positive
    if (formData.refillThreshold < 1) {
      newErrors.refillThreshold = "Threshold must be at least 1";
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  /**
   * Handle form submission
   */
  const handleSubmit = async (e) => {
    e.preventDefault();

    // Validate form
    if (!validateForm()) return;

    setLoading(true);
    try {
      await onAdd(formData);
    } catch (error) {
      console.error("Error adding medication:", error);
    } finally {
      setLoading(false);
    }
  };

  /**
   * Close modal when clicking outside
   */
  const handleBackdropClick = (e) => {
    if (e.target === e.currentTarget) {
      onClose();
    }
  };

  return (
    <div
      className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4"
      onClick={handleBackdropClick}
    >
      <div className="bg-white rounded-xl shadow-xl max-w-lg w-full max-h-[90vh] overflow-y-auto">
        {/* Modal Header */}
        <div className="flex items-center justify-between p-6 border-b border-gray-100">
          <div className="flex items-center space-x-3">
            <div className="bg-blue-100 p-2 rounded-lg">
              <svg
                className="w-6 h-6 text-blue-600"
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M12 4v16m8-8H4"
                />
              </svg>
            </div>
            <h2 className="text-xl font-bold text-gray-900">
              Add New Medication
            </h2>
          </div>
          <button
            onClick={onClose}
            className="text-gray-400 hover:text-gray-600 transition-colors"
          >
            <svg
              className="w-6 h-6"
              fill="none"
              stroke="currentColor"
              viewBox="0 0 24 24"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M6 18L18 6M6 6l12 12"
              />
            </svg>
          </button>
        </div>

        {/* Form */}
        <form onSubmit={handleSubmit} className="p-6 space-y-5">
          {/* Medicine Name */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              Medicine Name *
            </label>
            <input
              type="text"
              name="medicineName"
              value={formData.medicineName}
              onChange={handleChange}
              placeholder="e.g., Vitamin D3, Aspirin, Metformin"
              className={`input-field ${errors.medicineName ? "border-red-500 focus:ring-red-500" : ""}`}
            />
            {errors.medicineName && (
              <p className="mt-1 text-sm text-red-600">{errors.medicineName}</p>
            )}
          </div>

          {/* Total Quantity and Daily Dosage - Side by side */}
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Total Quantity (pills) *
              </label>
              <input
                type="number"
                name="totalQuantity"
                value={formData.totalQuantity}
                onChange={handleChange}
                min="1"
                className={`input-field ${errors.totalQuantity ? "border-red-500 focus:ring-red-500" : ""}`}
              />
              {errors.totalQuantity && (
                <p className="mt-1 text-sm text-red-600">
                  {errors.totalQuantity}
                </p>
              )}
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Daily Dosage (pills) *
              </label>
              <input
                type="number"
                name="dailyDosage"
                value={formData.dailyDosage}
                onChange={handleChange}
                min="1"
                className={`input-field ${errors.dailyDosage ? "border-red-500 focus:ring-red-500" : ""}`}
              />
              {errors.dailyDosage && (
                <p className="mt-1 text-sm text-red-600">
                  {errors.dailyDosage}
                </p>
              )}
            </div>
          </div>

          {/* Start Date */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              Start Date *
            </label>
            <input
              type="date"
              name="startDate"
              value={formData.startDate}
              onChange={handleChange}
              className={`input-field ${errors.startDate ? "border-red-500 focus:ring-red-500" : ""}`}
            />
            {errors.startDate && (
              <p className="mt-1 text-sm text-red-600">{errors.startDate}</p>
            )}
            <p className="mt-1 text-sm text-gray-500">
              When did you start taking this medication?
            </p>
          </div>

          {/* Refill Threshold */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              Refill Alert Threshold (pills)
            </label>
            <input
              type="number"
              name="refillThreshold"
              value={formData.refillThreshold}
              onChange={handleChange}
              min="1"
              className={`input-field ${errors.refillThreshold ? "border-red-500 focus:ring-red-500" : ""}`}
            />
            {errors.refillThreshold && (
              <p className="mt-1 text-sm text-red-600">
                {errors.refillThreshold}
              </p>
            )}
            <p className="mt-1 text-sm text-gray-500">
              You'll get an alert when remaining pills fall below this number.
            </p>
          </div>

          {/* Preview Box */}
          <div className="bg-blue-50 rounded-lg p-4 border border-blue-100">
            <h4 className="text-sm font-medium text-blue-800 mb-2">
              📊 Quick Preview
            </h4>
            <p className="text-sm text-blue-700">
              {formData.totalQuantity} pills at {formData.dailyDosage} pill
              {formData.dailyDosage > 1 ? "s" : ""}/day ={" "}
              <span className="font-bold">
                {Math.floor(formData.totalQuantity / formData.dailyDosage)} days
              </span>{" "}
              of supply
            </p>
          </div>

          {/* Form Actions */}
          <div className="flex space-x-3 pt-4">
            <button
              type="button"
              onClick={onClose}
              className="flex-1 btn-secondary"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={loading}
              className="flex-1 btn-primary disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {loading ? (
                <span className="flex items-center justify-center">
                  <svg
                    className="animate-spin -ml-1 mr-2 h-4 w-4 text-white"
                    fill="none"
                    viewBox="0 0 24 24"
                  >
                    <circle
                      className="opacity-25"
                      cx="12"
                      cy="12"
                      r="10"
                      stroke="currentColor"
                      strokeWidth="4"
                    ></circle>
                    <path
                      className="opacity-75"
                      fill="currentColor"
                      d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
                    ></path>
                  </svg>
                  Adding...
                </span>
              ) : (
                "Add Medication"
              )}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

export default AddMedication;
